import{Logger}from './logger.js';export class BaseComponent{constructor(name,options={}){if(new.target===BaseComponent){throw new Error('BaseComponent is abstract and cannot be instantiated directly');}this.name=name;this.options={debug: false,autoInit: true,...options};this.state={};this.listeners=new Map();this.initialized=false;if(this.options.autoInit){this.init();}}init(){if(this.initialized)return;this.debug('Initializing',this.name);this.setupState();this.render();this.bindEvents();this.initialized=true;this.onInit();}onInit(){}setupState(){this.state={...this.state};}render(){return `<div>${this.name}component</div>`;}bindEvents(){}setState(newState){const prevState={...this.state};this.state={...this.state,...newState};this.debug('State updated',prevState,'=>',this.state);this.render();this.onStateChange(prevState,newState);}onStateChange(prevState,newState){}on(target,event,handler,options={}){if(!target)return;target.addEventListener(event,handler,options);const listeners=this.listeners.get(target)||[];listeners.push({event,handler,options});this.listeners.set(target,listeners);}off(){this.listeners.forEach((listeners,target)=>{listeners.forEach(({event,handler,options})=>{target.removeEventListener(event,handler,options);});});this.listeners.clear();}debug(...args){if(this.options.debug){Logger.debug(`[${this.name}]`,...args);}}warn(...args){if(this.options.debug){Logger.warn(`[${this.name}]`,...args);}}error(...args){Logger.error(`[${this.name}]`,...args);}$(selector,context=document){if(typeof context==='string'){context=document.querySelector(context);}return context ? context.querySelector(selector): null;}$$(selector,context=document){if(typeof context==='string'){context=document.querySelector(context);}return context ? Array.from(context.querySelectorAll(selector)): [];}delegate(parent,selector,event,handler,options={}){this.on(parent,event,(e)=>{const target=e.target.closest(selector);if(target&&parent.contains(target)){handler.call(target,e);}},options);}destroy(){this.debug('Destroying component');this.off();this.onDestroy();this.initialized=false;}onDestroy(){}getInfo(){return{name: this.name,initialized: this.initialized,state:{...this.state},options:{...this.options}};}static initAll(selector,options={}){const instances=[];document.querySelectorAll(selector).forEach((el,index)=>{const component=new this({...options,element: el,index});instances.push(component);});return instances;}static initOnReady(selector,options={}){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{this.initAll(selector,options);});}else{this.initAll(selector,options);}}}export class BaseManager extends BaseComponent{constructor(name,options={}){super(name,{...options,autoInit: false});this.instances=new Map();}get(id,options={}){if(!this.instances.has(id)){const instance=this.create(id,options);this.instances.set(id,instance);}return this.instances.get(id);}create(id,options){this.debug('Creating instance:',id);return new BaseComponent(id,options);}remove(id){const instance=this.instances.get(id);if(instance&&typeof instance.destroy==='function'){instance.destroy();}this.instances.delete(id);}clear(){this.instances.forEach((instance,id)=>{this.remove(id);});this.instances.clear();}has(id){return this.instances.has(id);}}import{debounce,throttle,compose}from '../utils/function.js';export const ComponentUtils={debounce,throttle,compose,withLoading(fn,onStart,onEnd){return async function(...args){if(onStart)onStart();try{return await fn.apply(this,args);}finally{if(onEnd)onEnd();}};},withErrorHandling(fn,onError,defaultValue){return function(...args){try{return fn.apply(this,args);}catch(error){if(onError)onError(error);return defaultValue;}};}};if(typeof window!=='undefined'){window.BaseComponent=BaseComponent;window.BaseManager=BaseManager;window.ComponentUtils=ComponentUtils;}export default BaseComponent;